// Pull both ensures-foralls into the proof context so their triggers
// (post1_self_@.contains / post2_self_@.contains) are seeded for z3.
assert(forall|v: T|
    #![auto]
    post1_self_@.contains(v) ==>
        pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
assert(forall|v: T|
    #![auto]
    post2_self_@.contains(v) ==>
        pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));

// Both runs return the same first element of the pre-state.
assert(r1.0 == pre_self_@[0]);
assert(r2.0 == pre_self_@[0]);
assert(r1.0 == r2.0);

// Both runs return the same node index (get_node_ref is a spec fn, so
// equal inputs give equal outputs).
assert(r1.1 == pre_self_.get_node_ref(r1.0));
assert(r2.1 == pre_self_.get_node_ref(r2.0));
assert(r1.1 == r2.1);

// Hence the tuple results coincide.
assert(r1 == r2);

// Both post-states have the same length (pre_self_.len() - 1).
assert(post1_self_.len() == pre_self_.len() - 1);
assert(post2_self_.len() == pre_self_.len() - 1);
assert(post1_self_.len() == post2_self_.len());

// Both post-state views equal pre_self_@.skip(1), so they equal each other.
assert(post1_self_@ == pre_self_@.skip(1));
assert(post2_self_@ == pre_self_@.skip(1));
assert(post1_self_@ =~= post2_self_@);
assert(post1_self_@ == post2_self_@);

// On every element of the common post view, both post-states agree with
// pre_self_ on get_node_ref, hence with each other.
assert forall|v: T| post1_self_@.contains(v) implies
    post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
    assert(post2_self_@.contains(v));
}
assert forall|v: T| post2_self_@.contains(v) implies
    post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
    assert(post1_self_@.contains(v));
}
